// Migrate() now manages its own transactions and execution-strategy
// retries internally in EF Core 9. Wrapping it in an outer
// strategy.Execute + BeginTransaction caused nested retries and
// "Migrate was called inside a user transaction" errors.
void ApplyMigrations(AppDbContext db)
{
    db.Database.Migrate();
}

